// Build a single .vcf file for ONE contact per run.
// n8n runs this once per input item automatically.

const c = $input.item.json;

function esc(v) {
  if (v === null || v === undefined) return '';
  return String(v).replace(/\\/g, '\\\\').replace(/,/g, '\\,').replace(/;/g, '\\;').replace(/\n/g, '\\n');
}

function splitName(full) {
  if (!full) return { first: '', last: '' };
  const parts = String(full).trim().split(/\s+/);
  if (parts.length === 1) return { first: parts[0], last: '' };
  return { first: parts[0], last: parts.slice(1).join(' ') };
}

const { first, last } = splitName(c.name);
const lines = ['BEGIN:VCARD', 'VERSION:3.0'];
lines.push(`N:${esc(last)};${esc(first)};;;`);
lines.push(`FN:${esc(c.name || '')}`);
if (c.company) lines.push(`ORG:${esc(c.company)}`);
if (c.title) lines.push(`TITLE:${esc(c.title)}`);
if (c.email) lines.push(`EMAIL;TYPE=WORK:${esc(c.email)}`);

const phones = Array.isArray(c.phone) ? c.phone : (c.phone ? [c.phone] : []);
for (const p of phones) {
  if (p) lines.push(`TEL;TYPE=WORK,VOICE:${esc(p)}`);
}

if (c.website) lines.push(`URL:${esc(c.website)}`);
if (c.address) lines.push(`ADR;TYPE=WORK:;;${esc(c.address)};;;;`);
if (c.notes) lines.push(`NOTE:${esc(c.notes)}`);
lines.push('END:VCARD');

const vcfContent = lines.join('\r\n');
const safeName = (c.name || 'contact').replace(/[^a-z0-9]/gi, '-').toLowerCase();
const filename = `contact-${safeName}.vcf`;

return {
  json: {
    name: c.name,
    company: c.company,
    title: c.title,
    filename,
    chat_id: $('New Photo from Telegram').first().json.message.chat.id
  },
  binary: {
    data: {
      data: Buffer.from(vcfContent, 'utf8').toString('base64'),
      mimeType: 'text/vcard',
      fileName: filename,
      fileExtension: 'vcf'
    }
  }
};
